    ctx.fillText("双蛇对决", W / 2, 180);

    ctx.fillStyle = "#ffd54a";
    ctx.font = "bold 18px Arial";
    ctx.fillText("2分钟长度争霸战", W / 2, 215);

    ctx.fillStyle = "#d7e3ff";
    ctx.font = "15px Arial";
    const lines = [
      "红蛇：WASD    蓝蛇：方向键",
      "1. 撞到对方身体，自己死亡",
      "2. 死亡后3秒复活，长度重置为初始",
      "3. 时间结束后，长度更长的一方获胜",
      "4. 吃食物增长并获得分数"
    ];
    lines.forEach((line, i) => ctx.fillText(line, W / 2, 270 + i * 28));

    ctx.fillStyle = "#7CFF7A";
    ctx.font = "bold 20px Arial";
    ctx.fillText("按任意键或点击开始", W / 2, 470);
    ctx.restore();
  }

  function drawGameOver() {
    ctx.save();
    ctx.fillStyle = "rgba(0,0,0,0.52)";
    ctx.fillRect(0, 0, W, H);

    ctx.fillStyle = "#fff";
    ctx.textAlign = "center";
    ctx.font = "bold 30px Arial";
    ctx.fillText("比赛结束", W / 2, 220);

    ctx.fillStyle = "#ffe082";
    ctx.font = "bold 22px Arial";
    ctx.fillText(winnerText, W / 2, 265);

    ctx.fillStyle = snake1.color2;
    ctx.font = "16px Arial";
    ctx.fillText(`红蛇 - 长度:${snake1.segments.length}  分数:${snake1.score}  死亡:${snake1.deaths}`, W / 2, 320);

    ctx.fillStyle = snake2.color2;
    ctx.fillText(`蓝蛇 - 长度:${snake2.segments.length}  分数:${snake2.score}  死亡:${snake2.deaths}`, W / 2, 350);

    ctx.fillStyle = "#7CFF7A";
    ctx.font = "bold 18px Arial";
    ctx.fillText("按空格 / 回车 或 点击重新开始", W / 2, 430);
    ctx.restore();
  }

  function roundRect(ctx, x, y, w, h, r) {
    const rr = Math.min(r, w / 2, h / 2);
    ctx.beginPath();
    ctx.moveTo(x + rr, y);
    ctx.arcTo(x + w, y, x + w, y + h, rr);
    ctx.arcTo(x + w, y + h, x, y + h, rr);
    ctx.arcTo(x, y + h, x, y, rr);
    ctx.arcTo(x, y, x + w, y, rr);
    ctx.closePath();
  }

  function loop(now) {
    const dt = Math.min(50, now - lastTime);
    lastTime = now;

    if (gameState === "playing") {
      accumulator += dt;
      while (accumulator >= STEP_TIME) {
        update(STEP_TIME, now);
        accumulator -= STEP_TIME;
      }
    } else {
      updateParticles();
    }

    draw();
    requestAnimationFrame(loop);
  }

  draw();
  requestAnimationFrame((t) => {
    lastTime = t;
    loop(t);
  });
})();
